using System.Collections.Generic;

/// <summary>Tipo de valor guardado numa GameVariable.</summary>
public enum VariableType
{
    Bool,
    Int,
    Float,
    String
}

/// <summary>Onde uma variável vive: "Global" (GameVariables, partilhada por todo o jogo) ou "Local" (própria de um NpcController).</summary>
public enum VariableScope
{
    Global,
    Local
}

/// <summary>
/// Uma variável configurável no Inspector (Etapa 8): tem um nome, um tipo, e um
/// valor — apenas o campo correspondente a "type" é relevante. Permite criar
/// condições/eventos "trigger" sem código (ex: ligar a variável bool "porta_aberta"
/// numa ação, e condicionar outro evento a essa variável estar true).
/// </summary>
[System.Serializable]
public class GameVariable
{
    public string variableName;
    public VariableType type = VariableType.Bool;

    public bool boolValue;
    public int intValue;
    public float floatValue;
    public string stringValue;
}

/// <summary>
/// Operações de leitura/escrita sobre uma List&lt;GameVariable&gt; (variáveis
/// globais em GameVariables, ou locais num NpcController). Se a variável ainda
/// não existir, Get* devolve o valor por omissão e Set* cria-a automaticamente
/// (com o tipo correspondente) — útil para eventos feitos rapidamente no Editor
/// sem pré-declarar a variável, embora pré-declarar permita aproveitar a
/// verificação de nomes duplicados no Inspector.
/// </summary>
public static class GameVariableListUtil
{
    public static GameVariable Find(List<GameVariable> list, string name)
    {
        if (list == null || string.IsNullOrEmpty(name)) return null;

        foreach (var v in list)
            if (v != null && v.variableName == name) return v;

        return null;
    }

    private static GameVariable FindOrCreate(List<GameVariable> list, string name, VariableType type)
    {
        var v = Find(list, name);
        if (v == null)
        {
            v = new GameVariable { variableName = name, type = type };
            list.Add(v);
        }
        return v;
    }

    public static bool GetBool(List<GameVariable> list, string name, bool defaultValue = false)
    {
        var v = Find(list, name);
        return v != null ? v.boolValue : defaultValue;
    }

    public static int GetInt(List<GameVariable> list, string name, int defaultValue = 0)
    {
        var v = Find(list, name);
        return v != null ? v.intValue : defaultValue;
    }

    public static float GetFloat(List<GameVariable> list, string name, float defaultValue = 0f)
    {
        var v = Find(list, name);
        return v != null ? v.floatValue : defaultValue;
    }

    public static string GetString(List<GameVariable> list, string name, string defaultValue = "")
    {
        var v = Find(list, name);
        return v != null ? v.stringValue : defaultValue;
    }

    public static void SetBool(List<GameVariable> list, string name, bool value)
    {
        if (list == null || string.IsNullOrEmpty(name)) return;
        FindOrCreate(list, name, VariableType.Bool).boolValue = value;
    }

    public static void SetInt(List<GameVariable> list, string name, int value)
    {
        if (list == null || string.IsNullOrEmpty(name)) return;
        FindOrCreate(list, name, VariableType.Int).intValue = value;
    }

    public static void SetFloat(List<GameVariable> list, string name, float value)
    {
        if (list == null || string.IsNullOrEmpty(name)) return;
        FindOrCreate(list, name, VariableType.Float).floatValue = value;
    }

    public static void SetString(List<GameVariable> list, string name, string value)
    {
        if (list == null || string.IsNullOrEmpty(name)) return;
        FindOrCreate(list, name, VariableType.String).stringValue = value;
    }
}

/// <summary>
/// Ponte entre Actions/Conditions e as listas de variáveis: resolve "scope"
/// (Global → GameVariables.Instance; Local → npc.localVariables) e delega para
/// GameVariableListUtil. Usado por VariableActions / VariableConditions.
/// </summary>
public static class GameVariableUtil
{
    public static bool GetBool(NpcController npc, VariableScope scope, string name, bool defaultValue = false) =>
        scope == VariableScope.Global
            ? (GameVariables.Instance != null ? GameVariables.Instance.GetBool(name, defaultValue) : defaultValue)
            : (npc != null ? npc.GetLocalBool(name, defaultValue) : defaultValue);

    public static int GetInt(NpcController npc, VariableScope scope, string name, int defaultValue = 0) =>
        scope == VariableScope.Global
            ? (GameVariables.Instance != null ? GameVariables.Instance.GetInt(name, defaultValue) : defaultValue)
            : (npc != null ? npc.GetLocalInt(name, defaultValue) : defaultValue);

    public static float GetFloat(NpcController npc, VariableScope scope, string name, float defaultValue = 0f) =>
        scope == VariableScope.Global
            ? (GameVariables.Instance != null ? GameVariables.Instance.GetFloat(name, defaultValue) : defaultValue)
            : (npc != null ? npc.GetLocalFloat(name, defaultValue) : defaultValue);

    public static string GetString(NpcController npc, VariableScope scope, string name, string defaultValue = "") =>
        scope == VariableScope.Global
            ? (GameVariables.Instance != null ? GameVariables.Instance.GetString(name, defaultValue) : defaultValue)
            : (npc != null ? npc.GetLocalString(name, defaultValue) : defaultValue);

    public static void SetBool(NpcController npc, VariableScope scope, string name, bool value)
    {
        if (scope == VariableScope.Global) GameVariables.Instance?.SetBool(name, value);
        else npc?.SetLocalBool(name, value);
    }

    public static void SetInt(NpcController npc, VariableScope scope, string name, int value)
    {
        if (scope == VariableScope.Global) GameVariables.Instance?.SetInt(name, value);
        else npc?.SetLocalInt(name, value);
    }

    public static void SetFloat(NpcController npc, VariableScope scope, string name, float value)
    {
        if (scope == VariableScope.Global) GameVariables.Instance?.SetFloat(name, value);
        else npc?.SetLocalFloat(name, value);
    }

    public static void SetString(NpcController npc, VariableScope scope, string name, string value)
    {
        if (scope == VariableScope.Global) GameVariables.Instance?.SetString(name, value);
        else npc?.SetLocalString(name, value);
    }
}
